  onUpdate?: (po: PurchaseOrder) => void;
  onUpdateItemStatus?: (poId: string, partNumber: string, status: POItemStatus) => void;
  existingPO?: PurchaseOrder;
  logs?: LogEntry[];
  onGetSuggestion?: (item: POItem) => void;
