                               <div className="flex justify-between items-center">
                                 <div>
                                   <p className="font-bold text-slate-800 dark:text-slate-100">{item.partNumber}</p>
                                   <p className={`text-sm font-semibold ${getStatusColor(item.status)}`}>{item.status}</p>
                                 </div>
