                                >
                                    <ArrowDownTrayIcon className="w-5 h-5" />
                                    Export Filtered Data
                                </button>
                            </div>
                        </div>
                    )}

                    {/* --- MISSING OA TAB --- */}
                    {activeTab === 'missingOA' && (
                        <div className="space-y-4 h-full flex flex-col">
                            <div className="flex justify-between items-center mb-2">
