const ClosableOrdersModal: React.FC<{ isOpen: boolean; onClose: () => void; orders: PurchaseOrder[]; onSelectPO?: (po: PurchaseOrder) => void }> = ({ isOpen, onClose, orders, onSelectPO }) => {
    if (!isOpen) return null;

    return (
