            </div>
            <div className="flex-1 overflow-y-auto py-6 px-3">
                <ul className="space-y-3">
                    <NavItem 
                        icon={<HomeIcon className="w-6 h-6" />}
                        label="Dashboard"
                        isActive={activePane === 'dashboard'}
                        onClick={() => setActivePane('dashboard')}
