import React, { useState, useCallback, useMemo, useEffect } from 'react';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import POModal from './components/POModal';
import ProcurementSuggestionModal from './components/ProcurementSuggestionModal';
import Sidebar from './components/Sidebar';
import UploadPane from './components/UploadPane';
import AnalysisPane from './components/AnalysisPane';
import ConfirmationModal from './components/ConfirmationModal';
import AllOrdersPane from './components/AllOrdersPane';
import DataManagementPane from './components/DataManagementPane';
import ReportsPane from './components/ReportsPane';
import StockManagementPane from './components/StockManagementPane';
import ErrorBanner from './components/ErrorBanner';
import useLocalStorage from './hooks/useLocalStorage';
import { db, auth } from './services/firebase';
import { collection, onSnapshot, addDoc, doc, updateDoc, writeBatch, query, where, getDocs, serverTimestamp, Timestamp, orderBy, setDoc } from 'firebase/firestore';
import { signInAnonymously } from 'firebase/auth';

import { getProcurementSuggestion } from './services/geminiService';

import type { PurchaseOrder, Notification, LogEntry, POItem, ProcurementSuggestion, StockItem } from './types';
import { POItemStatus, OverallPOStatus, OrderStatus, FulfillmentStatus } from './types';

type ModalType = 'none' | 'poDetail' | 'suggestion';
type Pane = 'dashboard' | 'upload' | 'analysis' | 'allOrders' | 'dataManagement' | 'reports' | 'stockManagement';
type Theme = 'light' | 'dark';

function App() {
  const [purchaseOrders, setPurchaseOrders] = useState<PurchaseOrder[]>([]);
  const [stock, setStock] = useState<StockItem[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [activeModal, setActiveModal] = useState<ModalType>('none');
  const [activePane, setActivePane] = useState<Pane>('dashboard');
  const [theme, setTheme] = useLocalStorage<Theme>('theme', 'light');

  const [selectedPO, setSelectedPO] = useState<PurchaseOrder | null>(null);

  const [ordersFilter, setOrdersFilter] = useState<{
      status?: OverallPOStatus;
      fulfillmentStatus?: FulfillmentStatus;
  } | null>(null);

  const [suggestionItem, setSuggestionItem] = useState<POItem | null>(null);
  const [suggestion, setSuggestion] = useState<ProcurementSuggestion | null>(null);
  const [suggestionLoading, setSuggestionLoading] = useState(false);
  const [suggestionError, setSuggestionError] = useState<string | null>(null);

  const [filters, setFilters] = useState({
    status: '',
    customer: '',
    date: '',
    mainBranch: '',
    subBranch: '',
  });

  const [confirmationState, setConfirmationState] = useState<{
    isOpen: boolean;
    title: string;
    message: React.ReactNode;
    onConfirm?: () => void;
  }>({ isOpen: false, title: '', message: '' });

  const [firestoreError, setFirestoreError] = useState<string | null>(null);

  useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove(theme === 'light' ? 'dark' : 'light');
    root.classList.add(theme);
  }, [theme]);

  useEffect(() => {
    signInAnonymously(auth).catch(err => {
        console.warn("Auth check failed:", err.message);
    });

    const handleError = (error: any) => {
        const errorMessage = error instanceof Error ? error.message : String(error);
        if (error.code === 'permission-denied') {
            setFirestoreError('Database permission denied. Authentication required.');
        }
    };

    // Listen for POs
    const unsubPO = onSnapshot(query(collection(db, "purchaseOrders"), orderBy("createdAt", "desc")), (snapshot) => {
        const pos: PurchaseOrder[] = snapshot.docs.map(doc => {
            const data = doc.data();
            return {
                ...data,
                id: doc.id,
                createdAt: data.createdAt?.toDate ? data.createdAt.toDate().toISOString() : data.createdAt
            } as PurchaseOrder;
        });
        setPurchaseOrders(pos);
    }, handleError);

    // Listen for Stock
    const unsubStock = onSnapshot(collection(db, "stock"), (snapshot) => {
        const stocks: StockItem[] = snapshot.docs.map(doc => ({
            ...doc.data(),
            id: doc.id,
        } as StockItem));
        setStock(stocks);
    }, handleError);

    // Logs and Notifications
    const unsubLogs = onSnapshot(query(collection(db, "logs"), orderBy("timestamp", "desc")), (snapshot) => {
        const logsData = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as LogEntry));
        setLogs(logsData);
    }, handleError);

    const unsubNotifs = onSnapshot(query(collection(db, "notifications"), orderBy("createdAt", "desc")), (snapshot) => {
        const notifs = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as Notification));
        setNotifications(notifs);
    }, handleError);

    return () => {
        unsubPO();
        unsubStock();
        unsubLogs();
        unsubNotifs();
    };
}, [theme]);

  const addLog = async (poId: string, action: string) => {
    await addDoc(collection(db, "logs"), {
        poId,
        action,
        timestamp: serverTimestamp(),
    });
  };

  const addNotification = async (poId: string, message: string) => {
     await addDoc(collection(db, "notifications"), {
        poId,
        message,
        read: false,
        createdAt: serverTimestamp(),
    });
  };

  const handleUpdatePO = useCallback(async (updatedPO: PurchaseOrder) => {
    const poRef = doc(db, "purchaseOrders", updatedPO.id);
    await updateDoc(poRef, { ...updatedPO, items: updatedPO.items.map(i => ({ ...i })) });
    addLog(updatedPO.id, "PO updated.");
  }, []);

  const handleUpdateStock = async (partNumber: string, totalQty: number, description: string) => {
    const stockRef = doc(db, "stock", partNumber);
    const existing = stock.find(s => s.partNumber === partNumber);
    const allocated = existing ? existing.allocatedQuantity : 0;

    await setDoc(stockRef, {
        partNumber,
        description,
        totalQuantity: totalQty,
        allocatedQuantity: allocated,
        updatedAt: serverTimestamp()
    });
  };

  const handleTransferAllocation = async (sourcePoId: string, targetPoId: string, partNumber: string, quantity: number) => {
    const sourcePo = purchaseOrders.find(p => p.id === sourcePoId);
    const targetPo = purchaseOrders.find(p => p.id === targetPoId);
    if (!sourcePo || !targetPo) return;

    const batch = writeBatch(db);

    const newSourceItems = sourcePo.items.map(item => {
        if (item.partNumber === partNumber) {
            return { ...item, allocatedQuantity: Math.max(0, (item.allocatedQuantity || 0) - quantity) };
        }
        return item;
    });

    const newTargetItems = targetPo.items.map(item => {
        if (item.partNumber === partNumber) {
            return { ...item, allocatedQuantity: (item.allocatedQuantity || 0) + quantity };
        }
        return item;
    });

    batch.update(doc(db, "purchaseOrders", sourcePoId), { items: newSourceItems });
    batch.update(doc(db, "purchaseOrders", targetPoId), { items: newTargetItems });

    await batch.commit();
    addLog(sourcePoId, `Transferred ${quantity} units of ${partNumber} to PO #${targetPo.poNumber}`);
    addLog(targetPoId, `Received ${quantity} units of ${partNumber} from PO #${sourcePo.poNumber}`);
  };

  const handleBulkStockUpload = async (stockData: any[]) => {
    const batch = writeBatch(db);
    stockData.forEach(item => {
        const ref = doc(db, "stock", item.partNumber);
        batch.set(ref, {
            partNumber: item.partNumber,
            description: item.description || '',
            totalQuantity: Number(item.quantity) || 0,
            allocatedQuantity: 0,
            updatedAt: serverTimestamp()
        });
    });
    await batch.commit();
    alert("Stock database updated successfully.");
  };

  // Fix: Added handleSelectPO to open PO detail view
  const handleSelectPO = useCallback((po: PurchaseOrder) => {
    setSelectedPO(po);
    setActiveModal('poDetail');
  }, []);

  // Fix: Added handleCloseModal to reset modal state and selection
  const handleCloseModal = useCallback(() => {
    setActiveModal('none');
    setSelectedPO(null);
    setSuggestionItem(null);
    setSuggestion(null);
  }, []);

  // Fix: Added handleDashboardCardClick to handle navigation and filtering from dashboard
  const handleDashboardCardClick = useCallback((type: string) => {
    if (type === 'OPEN') {
      setOrdersFilter({ status: OverallPOStatus.Open });
    } else if (type === 'FULLY_AVAILABLE') {
      setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.Fulfillment });
    } else if (type === 'PARTIALLY_AVAILABLE') {
      setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.Partial });
    } else if (type === 'NOT_AVAILABLE') {
      setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.NotAvailable });
    }
    setActivePane('allOrders');
  }, []);

  // Fix: Added handleGetSuggestion to request procurement strategies from Gemini
  const handleGetSuggestion = async (item: POItem) => {
    setSuggestionItem(item);
    setSuggestionLoading(true);
    setSuggestionError(null);
    setActiveModal('suggestion');
    try {
      const result = await getProcurementSuggestion(item);
      setSuggestion(result);
    } catch (err) {
      setSuggestionError("Could not retrieve AI strategy at this time.");
    } finally {
      setSuggestionLoading(false);
    }
  };

  return (
    <div className="flex h-screen bg-slate-100 dark:bg-gray-900 text-slate-900 dark:text-slate-100 overflow-hidden">
       {firestoreError && <ErrorBanner projectId="maniranjan-po-dashboard" message={firestoreError} onDismiss={() => setFirestoreError(null)} />}
      <Sidebar activePane={activePane} setActivePane={setActivePane} />
       <div className="flex-1 flex flex-col">
        <Header notifications={notifications} onMarkNotificationsAsRead={() => {}} theme={theme} setTheme={setTheme} />
        <main className="flex-1 overflow-y-auto bg-slate-50 dark:bg-slate-900">
            {activePane === 'dashboard' && <Dashboard purchaseOrders={purchaseOrders} filters={filters} setFilters={setFilters} customers={[]} onCardClick={handleDashboardCardClick} />}
            {activePane === 'allOrders' && <AllOrdersPane purchaseOrders={purchaseOrders} onSelectPO={handleSelectPO} onDeletePO={() => {}} filter={ordersFilter} onClearFilter={() => setOrdersFilter(null)} />}
            {activePane === 'stockManagement' && (
                <StockManagementPane 
                    stock={stock} 
                    purchaseOrders={purchaseOrders} 
                    onUpdateStock={handleUpdateStock} 
                    onBulkUpload={handleBulkStockUpload}
                    onTransfer={handleTransferAllocation}
                />
            )}
            {activePane === 'upload' && <UploadPane onSaveSingleOrder={() => {}} onBulkUpload={() => {}} />}
            {activePane === 'analysis' && <AnalysisPane purchaseOrders={purchaseOrders} onSelectPO={handleSelectPO} />}
            {activePane === 'reports' && <ReportsPane purchaseOrders={purchaseOrders} onUpdatePO={handleUpdatePO} />}
            {activePane === 'dataManagement' && <DataManagementPane purchaseOrders={purchaseOrders} />}
        </main>
      </div>

       {selectedPO && (
        <POModal
          isOpen={activeModal === 'poDetail'}
          onClose={handleCloseModal}
          existingPO={selectedPO}
          logs={logs.filter(log => log.poId === selectedPO.id)}
          onUpdate={handleUpdatePO}
          onGetSuggestion={handleGetSuggestion}
        />
       )}

       <ProcurementSuggestionModal 
         isOpen={activeModal === 'suggestion'}
         onClose={() => setActiveModal('none')}
         item={suggestionItem}
         suggestion={suggestion}
         isLoading={suggestionLoading}
         error={suggestionError}
       />
    </div>
  );
}

export default App;

