import React, { useState, useMemo } from 'react';
import type { StockItem, PurchaseOrder } from '../types';
import { ArrowUpTrayIcon, PlusIcon, TruckIcon, XMarkIcon, MagnifyingGlassIcon, ArrowDownTrayIcon } from './icons';
import { downloadStockTemplate } from '../utils/export';

interface StockManagementPaneProps {
  stock: StockItem[];
  purchaseOrders: PurchaseOrder[];
  onUpdateStock: (partNumber: string, quantity: number, description: string) => Promise<void>;
  onBulkUpload: (stockData: any[]) => Promise<void>;
  onTransfer: (sourcePoId: string, targetPoId: string, partNumber: string, quantity: number) => Promise<void>;
}

const StockManagementPane: React.FC<StockManagementPaneProps> = ({ stock, purchaseOrders, onUpdateStock, onBulkUpload, onTransfer }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showTransferModal, setShowTransferModal] = useState(false);
  const [transferData, setTransferData] = useState({ sourcePoId: '', targetPoId: '', partNumber: '', quantity: 0 });

  const filteredStock = useMemo(() => {
    return stock.filter(s => 
        s.partNumber.toLowerCase().includes(searchTerm.toLowerCase()) || 
        s.description.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [stock, searchTerm]);

  const ordersWithPart = useMemo(() => {
    if (!transferData.partNumber) return [];
    return purchaseOrders.filter(po => 
        po.items.some(item => item.partNumber === transferData.partNumber && (item.allocatedQuantity || 0) > 0)
    );
  }, [purchaseOrders, transferData.partNumber]);

  const targetOrdersForPart = useMemo(() => {
    if (!transferData.partNumber) return [];
    return purchaseOrders.filter(po => 
        po.items.some(item => item.partNumber === transferData.partNumber) && po.id !== transferData.sourcePoId
    );
  }, [purchaseOrders, transferData.partNumber, transferData.sourcePoId]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const text = await file.text();
    const lines = text.split('\n').slice(1); // skip header
    const parsedData = lines.map(line => {
        const [partNumber, description, quantity] = line.split(',').map(s => s?.trim());
        return { partNumber, description, quantity };
    }).filter(d => d.partNumber);

    await onBulkUpload(parsedData);
  };

  const handleTransferSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!transferData.sourcePoId || !transferData.targetPoId || !transferData.partNumber || transferData.quantity <= 0) {
        alert("Invalid transfer details");
        return;
    }
    await onTransfer(transferData.sourcePoId, transferData.targetPoId, transferData.partNumber, transferData.quantity);
    setShowTransferModal(false);
    setTransferData({ sourcePoId: '', targetPoId: '', partNumber: '', quantity: 0 });
  };

  return (
    <div className="container mx-auto p-4 sm:p-6 lg:p-8 space-y-8">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-800 dark:text-white">Stock Inventory</h2>
          <p className="text-slate-500 dark:text-slate-400">Monitor physical stock and manage allocations.</p>
        </div>
        <div className="flex flex-wrap gap-2">
            <button 
                onClick={downloadStockTemplate}
                className="flex items-center gap-2 px-4 py-2 bg-slate-200 dark:bg-slate-700 text-slate-700 dark:text-slate-200 rounded-lg hover:bg-slate-300 dark:hover:bg-slate-600 transition-colors shadow-sm text-sm font-semibold"
            >
                <ArrowDownTrayIcon className="w-5 h-5" /> Template
            </button>
            <button 
                onClick={() => setShowTransferModal(true)}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors shadow-sm text-sm font-semibold"
            >
                <TruckIcon className="w-5 h-5" /> Transfer Allocation
            </button>
            <label className="flex items-center gap-2 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 cursor-pointer shadow-sm text-sm font-semibold">
                <ArrowUpTrayIcon className="w-5 h-5" />
                Upload Stock CSV
                <input type="file" className="hidden" accept=".csv" onChange={handleFileUpload} />
            </label>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-md border border-slate-200 dark:border-slate-700">
        <div className="relative mb-6">
          <MagnifyingGlassIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
          <input
            type="text"
            placeholder="Search stock by part number or description..."
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500 outline-none"
          />
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm border-collapse">
            <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-700 dark:text-slate-300 uppercase font-bold tracking-wider">
              <tr>
                <th className="p-4 border-b dark:border-slate-700">Part Number</th>
                <th className="p-4 border-b dark:border-slate-700">Description</th>
                <th className="p-4 border-b dark:border-slate-700 text-right">Physical Total</th>
                <th className="p-4 border-b dark:border-slate-700 text-right">Allocated</th>
                <th className="p-4 border-b dark:border-slate-700 text-right">Available</th>
              </tr>
            </thead>
            <tbody className="divide-y dark:divide-slate-700">
              {filteredStock.map(item => (
                <tr key={item.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors">
                  <td className="p-4 font-bold text-slate-900 dark:text-white">{item.partNumber}</td>
                  <td className="p-4 text-slate-600 dark:text-slate-400">{item.description}</td>
                  <td className="p-4 text-right font-medium">{item.totalQuantity}</td>
                  <td className="p-4 text-right text-red-500 font-medium">-{item.allocatedQuantity}</td>
                  <td className="p-4 text-right font-black text-green-600 dark:text-green-400 text-lg">
                    {item.totalQuantity - item.allocatedQuantity}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredStock.length === 0 && (
            <div className="p-12 text-center text-slate-500">No stock records found matching your search.</div>
          )}
        </div>
      </div>

      {/* Transfer Allocation Modal */}
      {showTransferModal && (
        <div className="fixed inset-0 bg-black bg-opacity-60 z-50 flex justify-center items-center p-4">
          <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl w-full max-w-xl overflow-hidden">
            <div className="flex justify-between items-center p-6 border-b dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50">
              <h3 className="text-xl font-bold text-slate-800 dark:text-white">Transfer Part Allocation</h3>
              <button onClick={() => setShowTransferModal(false)}><XMarkIcon className="w-6 h-6 text-slate-600 dark:text-slate-300" /></button>
            </div>
            <form onSubmit={handleTransferSubmit} className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-bold mb-1 text-slate-700 dark:text-slate-300">Part Number</label>
                <select 
                    className="w-full p-2.5 rounded-lg border dark:bg-slate-700 dark:border-slate-600 dark:text-white border-slate-300"
                    value={transferData.partNumber}
                    onChange={e => setTransferData({ ...transferData, partNumber: e.target.value, sourcePoId: '', targetPoId: '' })}
                >
                    <option value="">Select Part</option>
                    {stock.map(s => <option key={s.id} value={s.partNumber}>{s.partNumber} - {s.description}</option>)}
                </select>
              </div>

              {transferData.partNumber && (
                <>
                  <div>
                    <label className="block text-sm font-bold mb-1 text-slate-700 dark:text-slate-300">Source PO (Decreasing Allocation)</label>
                    <select 
                        className="w-full p-2.5 rounded-lg border dark:bg-slate-700 dark:border-slate-600 dark:text-white border-slate-300"
                        value={transferData.sourcePoId}
                        onChange={e => setTransferData({ ...transferData, sourcePoId: e.target.value })}
                    >
                        <option value="">Select Source PO</option>
                        {ordersWithPart.map(po => (
                            <option key={po.id} value={po.id}>#{po.poNumber} - {po.customerName}</option>
                        ))}
                    </select>
                  </div>

                  <div>
                    <label className="block text-sm font-bold mb-1 text-slate-700 dark:text-slate-300">Target PO (Increasing Allocation)</label>
                    <select 
                        className="w-full p-2.5 rounded-lg border dark:bg-slate-700 dark:border-slate-600 dark:text-white border-slate-300"
                        value={transferData.targetPoId}
                        onChange={e => setTransferData({ ...transferData, targetPoId: e.target.value })}
                    >
                        <option value="">Select Target PO</option>
                        {targetOrdersForPart.map(po => (
                            <option key={po.id} value={po.id}>#{po.poNumber} - {po.customerName}</option>
                        ))}
                    </select>
                  </div>

                  <div>
                    <label className="block text-sm font-bold mb-1 text-slate-700 dark:text-slate-300">Quantity to Transfer</label>
                    <input 
                        type="number"
                        className="w-full p-2.5 rounded-lg border dark:bg-slate-700 dark:border-slate-600 dark:text-white border-slate-300"
                        value={transferData.quantity}
                        onChange={e => setTransferData({ ...transferData, quantity: Number(e.target.value) })}
                    />
                  </div>
                </>
              )}

              <div className="pt-4 flex justify-end gap-3">
                <button type="button" onClick={() => setShowTransferModal(false)} className="px-4 py-2 text-slate-500 dark:text-slate-400">Cancel</button>
                <button type="submit" className="px-6 py-2 bg-blue-600 text-white rounded-lg font-bold">Perform Transfer</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

