import { db, auth } from './services/firebase';
import { collection, onSnapshot, addDoc, doc, updateDoc, writeBatch, query, where, getDocs, serverTimestamp, Timestamp, orderBy, setDoc } from 'firebase/firestore';
import { signInAnonymously } from 'firebase/auth';

import { getProcurementSuggestion } from './services/geminiService';

import type { PurchaseOrder, Notification, LogEntry, POItem, ProcurementSuggestion, StockItem, StockMovement } from './types';
import { POItemStatus, OverallPOStatus, OrderStatus, FulfillmentStatus } from './types';

type ModalType = 'none' | 'poDetail' | 'suggestion';
type Pane = 'dashboard' | 'upload' | 'analysis' | 'allOrders' | 'dataManagement' | 'reports' | 'stockManagement';
type Theme = 'light' | 'dark';

function App() {
  const [purchaseOrders, setPurchaseOrders] = useState<PurchaseOrder[]>([]);
  const [stock, setStock] = useState<StockItem[]>([]);
  const [stockMovements, setStockMovements] = useState<StockMovement[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [activeModal, setActiveModal] = useState<ModalType>('none');
  const [activePane, setActivePane] = useState<Pane>('dashboard');
  const [theme, setTheme] = useLocalStorage<Theme>('theme', 'light');

  const [selectedPO, setSelectedPO] = useState<PurchaseOrder | null>(null);

  const [ordersFilter, setOrdersFilter] = useState<{
      status?: OverallPOStatus;
      fulfillmentStatus?: FulfillmentStatus;
  } | null>(null);

  const [suggestionItem, setSuggestionItem] = useState<POItem | null>(null);
  const [suggestion, setSuggestion] = useState<ProcurementSuggestion | null>(null);
  const [suggestionLoading, setSuggestionLoading] = useState(false);
  const [suggestionError, setSuggestionError] = useState<string | null>(null);

  const [filters, setFilters] = useState({
    status: '',
    customer: '',
    date: '',
    mainBranch: '',
    subBranch: '',
  });

  const [firestoreError, setFirestoreError] = useState<string | null>(null);

  useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove(theme === 'light' ? 'dark' : 'light');
    root.classList.add(theme);
  }, [theme]);

  useEffect(() => {
    signInAnonymously(auth).catch(err => {
        console.warn("Auth check failed:", err.message);
    });

    const handleError = (error: any) => {
        if (error.code === 'permission-denied') {
            setFirestoreError('Database permission denied. Authentication required.');
        }
    };

    const unsubPO = onSnapshot(query(collection(db, "purchaseOrders"), orderBy("createdAt", "desc")), (snapshot) => {
        const pos = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as PurchaseOrder));
        setPurchaseOrders(pos);
    }, handleError);

    const unsubStock = onSnapshot(collection(db, "stock"), (snapshot) => {
        const stocks = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as StockItem));
        setStock(stocks);
    }, handleError);

    const unsubMovements = onSnapshot(query(collection(db, "stockMovements"), orderBy("timestamp", "desc")), (snapshot) => {
        const mvts = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as StockMovement));
        setStockMovements(mvts);
    }, handleError);

    const unsubLogs = onSnapshot(query(collection(db, "logs"), orderBy("timestamp", "desc")), (snapshot) => {
        const logsData = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as LogEntry));
        setLogs(logsData);
    }, handleError);

    const unsubNotifs = onSnapshot(query(collection(db, "notifications"), orderBy("createdAt", "desc")), (snapshot) => {
        const notifs = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as Notification));
        setNotifications(notifs);
    }, handleError);

    return () => {
        unsubPO(); unsubStock(); unsubMovements(); unsubLogs(); unsubNotifs();
    };
}, [theme]);

  const addLog = async (poId: string, action: string) => {
    await addDoc(collection(db, "logs"), { poId, action, timestamp: serverTimestamp() });
  };

  const logStockMovement = async (mvt: Omit<StockMovement, 'id' | 'timestamp'>) => {
    await addDoc(collection(db, "stockMovements"), { ...mvt, timestamp: serverTimestamp() });
  };

  const handleUpdatePO = useCallback(async (updatedPO: PurchaseOrder) => {
    const poRef = doc(db, "purchaseOrders", updatedPO.id);
    await updateDoc(poRef, { ...updatedPO });
    addLog(updatedPO.id, "PO updated.");
  }, []);

  const handleInwardStock = async (partNumber: string, qty: number, remark: string) => {
    const stockRef = doc(db, "stock", partNumber);
    const existing = stock.find(s => s.partNumber === partNumber);
    const newTotal = (existing?.totalQuantity || 0) + qty;

    await setDoc(stockRef, {
        partNumber,
        description: existing?.description || 'Inward Entry',
        totalQuantity: newTotal,
        allocatedQuantity: existing?.allocatedQuantity || 0,
        updatedAt: serverTimestamp()
    }, { merge: true });

    await logStockMovement({
        partNumber,
        type: 'INWARD',
        quantity: qty,
        remarks: `Inward: ${remark}`
    });
  };

  const handleWalkingSale = async (partNumber: string, qty: number, remark: string) => {
    const stockRef = doc(db, "stock", partNumber);
    const existing = stock.find(s => s.partNumber === partNumber);
    if (!existing || (existing.totalQuantity - existing.allocatedQuantity) < qty) {
        alert("Insufficient available stock for walking sale.");
        return;
    }

    const newTotal = existing.totalQuantity - qty;
    await updateDoc(stockRef, { totalQuantity: newTotal, updatedAt: serverTimestamp() });

    await logStockMovement({
        partNumber,
        type: 'OUTWARD_WALKING',
        quantity: qty,
        remarks: `Walking Sale: ${remark}`
    });
  };

  const handleAllocateStock = async (poId: string, partNumber: string, qty: number) => {
    const targetPo = purchaseOrders.find(p => p.id === poId);
    const targetStock = stock.find(s => s.partNumber === partNumber);

    if (!targetPo || !targetStock) return;
    if ((targetStock.totalQuantity - targetStock.allocatedQuantity) < qty) {
        alert("Insufficient physical stock to allocate.");
        return;
    }

    const batch = writeBatch(db);

    const newItems = targetPo.items.map(item => {
        if (item.partNumber === partNumber) {
            return { ...item, allocatedQuantity: (item.allocatedQuantity || 0) + qty };
        }
        return item;
    });

    batch.update(doc(db, "purchaseOrders", poId), { items: newItems });
    batch.update(doc(db, "stock", partNumber), { 
        allocatedQuantity: (targetStock.allocatedQuantity || 0) + qty,
        updatedAt: serverTimestamp()
    });

    await batch.commit();
    await logStockMovement({
        partNumber,
        type: 'ALLOCATION',
        quantity: qty,
        referenceId: poId,
        remarks: `Allocated to PO #${targetPo.poNumber}`
    });
    addLog(poId, `Allocated ${qty} units of ${partNumber} from stock.`);
  };

  const handleSelectPO = useCallback((po: PurchaseOrder) => {
    setSelectedPO(po);
    setActiveModal('poDetail');
  }, []);

  const handleCloseModal = useCallback(() => {
    setActiveModal('none');
    setSelectedPO(null);
  }, []);

  const handleDashboardCardClick = useCallback((type: string) => {
    if (type === 'OPEN') setOrdersFilter({ status: OverallPOStatus.Open });
    else if (type === 'FULLY_AVAILABLE') setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.Fulfillment });
    else if (type === 'PARTIALLY_AVAILABLE') setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.Partial });
    else if (type === 'NOT_AVAILABLE') setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.NotAvailable });
    setActivePane('allOrders');
  }, []);

  return (
    <div className="flex h-screen bg-slate-100 dark:bg-gray-900 text-slate-900 dark:text-slate-100 overflow-hidden">
       {firestoreError && <ErrorBanner projectId="maniranjan-po" message={firestoreError} onDismiss={() => setFirestoreError(null)} />}
      <Sidebar activePane={activePane} setActivePane={setActivePane} />
       <div className="flex-1 flex flex-col">
        <Header notifications={notifications} onMarkNotificationsAsRead={() => {}} theme={theme} setTheme={setTheme} />
        <main className="flex-1 overflow-y-auto bg-slate-50 dark:bg-slate-900">
            {activePane === 'dashboard' && <Dashboard purchaseOrders={purchaseOrders} filters={filters} setFilters={setFilters} customers={[]} onCardClick={handleDashboardCardClick} />}
            {activePane === 'allOrders' && <AllOrdersPane purchaseOrders={purchaseOrders} onSelectPO={handleSelectPO} onDeletePO={() => {}} filter={ordersFilter} onClearFilter={() => setOrdersFilter(null)} />}
            {activePane === 'stockManagement' && (
                <StockManagementPane 
                    stock={stock} 
                    purchaseOrders={purchaseOrders} 
                    movements={stockMovements}
                    onInward={handleInwardStock}
                    onWalkingSale={handleWalkingSale}
                    onAllocate={handleAllocateStock}
                />
            )}
            {activePane === 'upload' && <UploadPane onSaveSingleOrder={() => {}} onBulkUpload={() => {}} />}
            {activePane === 'analysis' && <AnalysisPane purchaseOrders={purchaseOrders} onSelectPO={handleSelectPO} />}
            {activePane === 'reports' && <ReportsPane purchaseOrders={purchaseOrders} onUpdatePO={handleUpdatePO} />}
            {activePane === 'dataManagement' && <DataManagementPane purchaseOrders={purchaseOrders} />}
        </main>
      </div>

       {selectedPO && (
        <POModal
          isOpen={activeModal === 'poDetail'}
          onClose={handleCloseModal}
          existingPO={selectedPO}
          logs={logs.filter(log => log.poId === selectedPO.id)}
          onUpdate={handleUpdatePO}
        />
       )}
    </div>
  );
}

export default App;

import React, { useState, useMemo } from 'react';
import type { StockItem, PurchaseOrder, StockMovement } from '../types';
import { ArrowUpTrayIcon, TruckIcon, XMarkIcon, MagnifyingGlassIcon, ArrowDownTrayIcon, PlusIcon, CurrencyRupeeIcon, ClockIcon, ClipboardDocumentListIcon } from './icons';
import { downloadStockTemplate } from '../utils/export';

interface StockManagementPaneProps {
  stock: StockItem[];
  purchaseOrders: PurchaseOrder[];
  movements: StockMovement[];
  onInward: (partNumber: string, qty: number, remark: string) => Promise<void>;
  onWalkingSale: (partNumber: string, qty: number, remark: string) => Promise<void>;
  onAllocate: (poId: string, partNumber: string, qty: number) => Promise<void>;
}

const StockManagementPane: React.FC<StockManagementPaneProps> = ({ stock, purchaseOrders, movements, onInward, onWalkingSale, onAllocate }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [activeModal, setActiveModal] = useState<'inward' | 'walking' | 'allocate' | 'history' | null>(null);
  const [selectedPart, setSelectedPart] = useState<string | null>(null);

  const [formState, setFormState] = useState({ qty: 1, remark: '', poId: '' });

  const filteredStock = useMemo(() => {
    return stock.filter(s => 
        s.partNumber.toLowerCase().includes(searchTerm.toLowerCase()) || 
        s.description.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [stock, searchTerm]);

  const partHistory = useMemo(() => {
    if (!selectedPart) return [];
    return movements.filter(m => m.partNumber === selectedPart);
  }, [movements, selectedPart]);

  const targetPOsForPart = useMemo(() => {
    if (!selectedPart) return [];
    return purchaseOrders.filter(po => 
        po.items.some(item => item.partNumber === selectedPart && (item.quantity - (item.allocatedQuantity || 0)) > 0)
    );
  }, [purchaseOrders, selectedPart]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPart) return;

    if (activeModal === 'inward') {
        await onInward(selectedPart, formState.qty, formState.remark);
    } else if (activeModal === 'walking') {
        await onWalkingSale(selectedPart, formState.qty, formState.remark);
    } else if (activeModal === 'allocate') {
        await onAllocate(formState.poId, selectedPart, formState.qty);
    }
    setActiveModal(null);
    setFormState({ qty: 1, remark: '', poId: '' });
  };

  return (
    <div className="container mx-auto p-4 sm:p-6 lg:p-8 space-y-8">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-800 dark:text-white">Inventory Control</h2>
          <p className="text-slate-500 dark:text-slate-400">Physical stock tracking, inward entries, and PO allocations.</p>
        </div>
        <div className="flex flex-wrap gap-2">
            <button 
                onClick={downloadStockTemplate}
                className="flex items-center gap-2 px-4 py-2 bg-slate-200 dark:bg-slate-700 text-slate-700 dark:text-slate-200 rounded-lg hover:bg-slate-300 dark:hover:bg-slate-600 transition-colors shadow-sm text-sm font-semibold"
            >
                <ArrowDownTrayIcon className="w-5 h-5" /> Template
            </button>
            <label className="flex items-center gap-2 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 cursor-pointer shadow-sm text-sm font-semibold">
                <ArrowUpTrayIcon className="w-5 h-5" />
                Bulk Inward CSV
                <input type="file" className="hidden" accept=".csv" />
            </label>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-md border border-slate-200 dark:border-slate-700">
        <div className="relative mb-6">
          <MagnifyingGlassIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
          <input
            type="text"
            placeholder="Search parts inventory..."
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-3 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-red-500 focus:border-red-500 outline-none shadow-sm"
          />
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm border-collapse">
            <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-700 dark:text-slate-300 uppercase font-bold tracking-wider">
              <tr>
                <th className="p-4 border-b dark:border-slate-700">Part Info</th>
                <th className="p-4 border-b dark:border-slate-700 text-right">Physical Total</th>
                <th className="p-4 border-b dark:border-slate-700 text-right">Allocated</th>
                <th className="p-4 border-b dark:border-slate-700 text-right">Net Available</th>
                <th className="p-4 border-b dark:border-slate-700 text-center">Quick Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y dark:divide-slate-700">
              {filteredStock.map(item => (
                <tr key={item.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors group">
                  <td className="p-4">
                    <p className="font-bold text-slate-900 dark:text-white text-base">{item.partNumber}</p>
                    <p className="text-slate-500 dark:text-slate-400 text-xs truncate max-w-xs">{item.description}</p>
                  </td>
                  <td className="p-4 text-right font-medium text-lg">{item.totalQuantity}</td>
                  <td className="p-4 text-right text-red-500 font-medium">-{item.allocatedQuantity}</td>
                  <td className="p-4 text-right">
                    <span className={`font-black text-xl ${item.totalQuantity - item.allocatedQuantity > 0 ? 'text-green-600 dark:text-green-400' : 'text-slate-400'}`}>
                        {item.totalQuantity - item.allocatedQuantity}
                    </span>
                  </td>
                  <td className="p-4">
                    <div className="flex justify-center gap-1">
                        <button 
                            onClick={() => { setSelectedPart(item.partNumber); setActiveModal('inward'); }}
                            className="p-2 text-green-600 hover:bg-green-50 dark:hover:bg-green-900/20 rounded-lg title='Inward Stock'"
                        >
                            <PlusIcon className="w-5 h-5" />
                        </button>
                        <button 
                             onClick={() => { setSelectedPart(item.partNumber); setActiveModal('walking'); }}
                             className="p-2 text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg title='Walking Sale'"
                        >
                            <CurrencyRupeeIcon className="w-5 h-5" />
                        </button>
                        <button 
                             onClick={() => { setSelectedPart(item.partNumber); setActiveModal('allocate'); }}
                             className="p-2 text-amber-600 hover:bg-amber-50 dark:hover:bg-amber-900/20 rounded-lg title='Allocate to PO'"
                        >
                            <TruckIcon className="w-5 h-5" />
                        </button>
                        <button 
                             onClick={() => { setSelectedPart(item.partNumber); setActiveModal('history'); }}
                             className="p-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg title='History'"
                        >
                            <ClockIcon className="w-5 h-5" />
                        </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredStock.length === 0 && (
            <div className="p-12 text-center text-slate-500 italic">No inventory records found.</div>
          )}
        </div>
      </div>

      {/* Stock Adjust Modal (Combined for Inward, Walking, Allocation) */}
      {activeModal && activeModal !== 'history' && (
        <div className="fixed inset-0 bg-black bg-opacity-60 z-50 flex justify-center items-center p-4">
          <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden border dark:border-slate-700">
            <div className="flex justify-between items-center p-6 border-b dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50">
              <h3 className="text-xl font-bold text-slate-800 dark:text-white capitalize">
                {activeModal.replace('_', ' ')} Stock: {selectedPart}
              </h3>
              <button onClick={() => setActiveModal(null)}><XMarkIcon className="w-6 h-6" /></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-5">
              {activeModal === 'allocate' && (
                <div>
                  <label className="block text-sm font-bold mb-1.5 text-slate-700 dark:text-slate-300 uppercase tracking-tight">Target Purchase Order</label>
                  <select 
                      required
                      className="w-full p-3 rounded-lg border dark:bg-slate-700 dark:border-slate-600 dark:text-white border-slate-300 focus:ring-2 focus:ring-amber-500"
                      value={formState.poId}
                      onChange={e => setFormState({ ...formState, poId: e.target.value })}
                  >
                      <option value="">Select Pending PO</option>
                      {targetPOsForPart.map(po => (
                          <option key={po.id} value={po.id}>#{po.poNumber} - {po.customerName}</option>
                      ))}
                  </select>
                </div>
              )}

              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-1">
                    <label className="block text-sm font-bold mb-1.5 text-slate-700 dark:text-slate-300 uppercase tracking-tight">Quantity</label>
                    <input 
                        type="number"
                        min="1"
                        required
                        className="w-full p-3 rounded-lg border dark:bg-slate-700 dark:border-slate-600 dark:text-white border-slate-300 focus:ring-2 focus:ring-red-500"
                        value={formState.qty}
                        onChange={e => setFormState({ ...formState, qty: Number(e.target.value) })}
                    />
                </div>
                <div className="col-span-1 flex items-end">
                    <p className="text-xs text-slate-500 dark:text-slate-400 pb-2">
                        {activeModal === 'allocate' ? 'Max Req: Use PO Details' : 'Physical Units'}
                    </p>
                </div>
              </div>

              <div>
                <label className="block text-sm font-bold mb-1.5 text-slate-700 dark:text-slate-300 uppercase tracking-tight">Remarks / Reference</label>
                <textarea 
                    className="w-full p-3 rounded-lg border dark:bg-slate-700 dark:border-slate-600 dark:text-white border-slate-300 focus:ring-2 focus:ring-red-500"
                    placeholder={activeModal === 'inward' ? 'e.g., Supplier Invoice #991' : 'e.g., Walk-in customer cash sale'}
                    value={formState.remark}
                    rows={2}
                    onChange={e => setFormState({ ...formState, remark: e.target.value })}
                />
              </div>

              <div className="pt-4 flex justify-end gap-3">
                <button type="button" onClick={() => setActiveModal(null)} className="px-5 py-2.5 text-slate-500 font-bold hover:text-slate-700 transition-colors">Cancel</button>
                <button type="submit" className={`px-8 py-2.5 rounded-lg font-bold text-white shadow-lg transition-transform active:scale-95 ${activeModal === 'inward' ? 'bg-green-600' : activeModal === 'allocate' ? 'bg-amber-600' : 'bg-blue-600'}`}>
                    Confirm {activeModal}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* History Modal */}
      {activeModal === 'history' && (
        <div className="fixed inset-0 bg-black bg-opacity-60 z-50 flex justify-center items-center p-4">
          <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden border dark:border-slate-700">
            <div className="flex justify-between items-center p-6 border-b dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50">
               <div className="flex items-center gap-2">
                 <ClipboardDocumentListIcon className="w-6 h-6 text-slate-500" />
                 <h3 className="text-xl font-bold text-slate-800 dark:text-white">Movement Log: {selectedPart}</h3>
               </div>
               <button onClick={() => setActiveModal(null)}><XMarkIcon className="w-6 h-6" /></button>
            </div>
            <div className="p-6 max-h-[60vh] overflow-y-auto">
                <div className="space-y-4">
                    {partHistory.length > 0 ? partHistory.map(m => (
                        <div key={m.id} className="flex items-start gap-4 p-4 rounded-xl border dark:border-slate-700 bg-slate-50 dark:bg-slate-900/30">
                            <div className={`p-2 rounded-full flex-shrink-0 ${
                                m.type === 'INWARD' ? 'bg-green-100 text-green-600' : 
                                m.type === 'OUTWARD_WALKING' ? 'bg-blue-100 text-blue-600' : 
                                'bg-amber-100 text-amber-600'
                            }`}>
                                {m.type === 'INWARD' ? <PlusIcon className="w-5 h-5" /> : m.type === 'OUTWARD_WALKING' ? <CurrencyRupeeIcon className="w-5 h-5" /> : <TruckIcon className="w-5 h-5" />}
                            </div>
                            <div className="flex-1">
                                <div className="flex justify-between">
                                    <p className="font-bold text-slate-800 dark:text-white capitalize">{m.type.replace('_', ' ').toLowerCase()}</p>
                                    <p className="text-xs text-slate-500">{new Date(m.timestamp).toLocaleString()}</p>
                                </div>
                                <p className="text-sm text-slate-600 dark:text-slate-400 mt-1">{m.remarks}</p>
                                <p className="text-base font-black mt-2">
                                    {m.type === 'INWARD' ? '+' : '-'} {m.quantity} Units
                                </p>
                            </div>
                        </div>
                    )) : (
                        <div className="text-center py-10 text-slate-500 italic">No movements recorded yet.</div>
                    )}
                </div>
            </div>
            <div className="p-4 bg-slate-50 dark:bg-slate-900/50 border-t dark:border-slate-700 flex justify-end">
                <button onClick={() => setActiveModal(null)} className="px-6 py-2 bg-slate-800 text-white rounded-lg font-bold">Close</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default StockManagementPane;

import React, { useState, useMemo } from 'react';
import type { StockItem, PurchaseOrder, StockMovement } from '../types';
import { ArrowUpTrayIcon, TruckIcon, XMarkIcon, MagnifyingGlassIcon, ArrowDownTrayIcon, PlusIcon, CurrencyRupeeIcon, ClockIcon, ClipboardDocumentListIcon } from './icons';
import { downloadStockTemplate } from '../utils/export';

interface StockManagementPaneProps {
  stock: StockItem[];
  purchaseOrders: PurchaseOrder[];
  movements: StockMovement[];
  onInward: (partNumber: string, qty: number, remark: string) => Promise<void>;
  onWalkingSale: (partNumber: string, qty: number, remark: string) => Promise<void>;
  onAllocate: (poId: string, partNumber: string, qty: number) => Promise<void>;
}

const StockManagementPane: React.FC<StockManagementPaneProps> = ({ stock, purchaseOrders, movements, onInward, onWalkingSale, onAllocate }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [activeModal, setActiveModal] = useState<'inward' | 'walking' | 'allocate' | 'history' | null>(null);
  const [selectedPart, setSelectedPart] = useState<string | null>(null);

  // Search filter for PO allocation
