import React, { useState, useCallback, useMemo, useEffect } from 'react';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import POModal from './components/POModal';
import ProcurementSuggestionModal from './components/ProcurementSuggestionModal';
import Sidebar from './components/Sidebar';
import UploadPane from './components/UploadPane';
import AnalysisPane from './components/AnalysisPane';
import ConfirmationModal from './components/ConfirmationModal';
import AllOrdersPane from './components/AllOrdersPane';
import DataManagementPane from './components/DataManagementPane';
import ReportsPane from './components/ReportsPane';
import StockManagementPane from './components/StockManagementPane';
import ErrorBanner from './components/ErrorBanner';
import useLocalStorage from './hooks/useLocalStorage';
import { db, auth } from './services/firebase';
import { collection, onSnapshot, addDoc, doc, updateDoc, writeBatch, query, where, getDocs, serverTimestamp, Timestamp, orderBy, setDoc } from 'firebase/firestore';
import { signInAnonymously } from 'firebase/auth';

import { getProcurementSuggestion } from './services/geminiService';

import type { PurchaseOrder, Notification, LogEntry, POItem, ProcurementSuggestion, StockItem, StockMovement } from './types';
import { POItemStatus, OverallPOStatus, OrderStatus, FulfillmentStatus } from './types';

type ModalType = 'none' | 'poDetail' | 'suggestion';
type Pane = 'dashboard' | 'upload' | 'analysis' | 'allOrders' | 'dataManagement' | 'reports' | 'stockManagement';
type Theme = 'light' | 'dark';

function App() {
  const [purchaseOrders, setPurchaseOrders] = useState<PurchaseOrder[]>([]);
  const [stock, setStock] = useState<StockItem[]>([]);
  const [stockMovements, setStockMovements] = useState<StockMovement[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [activeModal, setActiveModal] = useState<ModalType>('none');
  const [activePane, setActivePane] = useState<Pane>('dashboard');
  const [theme, setTheme] = useLocalStorage<Theme>('theme', 'light');

  const [selectedPO, setSelectedPO] = useState<PurchaseOrder | null>(null);

  const [ordersFilter, setOrdersFilter] = useState<{
      status?: OverallPOStatus;
      fulfillmentStatus?: FulfillmentStatus;
  } | null>(null);

  const [suggestionItem, setSuggestionItem] = useState<POItem | null>(null);
  const [suggestion, setSuggestion] = useState<ProcurementSuggestion | null>(null);
  const [suggestionLoading, setSuggestionLoading] = useState(false);
  const [suggestionError, setSuggestionError] = useState<string | null>(null);

  const [filters, setFilters] = useState({
    status: '',
    customer: '',
    date: '',
    mainBranch: '',
    subBranch: '',
  });

  const [firestoreError, setFirestoreError] = useState<string | null>(null);

  useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove(theme === 'light' ? 'dark' : 'light');
    root.classList.add(theme);
  }, [theme]);

  useEffect(() => {
    signInAnonymously(auth).catch(err => {
        console.warn("Auth check failed:", err.message);
    });

    const handleError = (error: any) => {
        if (error.code === 'permission-denied') {
            setFirestoreError('Database permission denied. Authentication required.');
        }
    };

    const unsubPO = onSnapshot(query(collection(db, "purchaseOrders"), orderBy("createdAt", "desc")), (snapshot) => {
        const pos = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as PurchaseOrder));
        setPurchaseOrders(pos);
    }, handleError);

    const unsubStock = onSnapshot(collection(db, "stock"), (snapshot) => {
        const stocks = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as StockItem));
        setStock(stocks);
    }, handleError);

    const unsubMovements = onSnapshot(query(collection(db, "stockMovements"), orderBy("timestamp", "desc")), (snapshot) => {
        const mvts = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as StockMovement));
        setStockMovements(mvts);
    }, handleError);

    const unsubLogs = onSnapshot(query(collection(db, "logs"), orderBy("timestamp", "desc")), (snapshot) => {
        const logsData = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as LogEntry));
        setLogs(logsData);
    }, handleError);

    const unsubNotifs = onSnapshot(query(collection(db, "notifications"), orderBy("createdAt", "desc")), (snapshot) => {
        const notifs = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as Notification));
        setNotifications(notifs);
    }, handleError);

    return () => {
        unsubPO(); unsubStock(); unsubMovements(); unsubLogs(); unsubNotifs();
    };
}, [theme]);

  const addLog = async (poId: string, action: string) => {
    await addDoc(collection(db, "logs"), { poId, action, timestamp: serverTimestamp() });
  };

  const logStockMovement = async (mvt: Omit<StockMovement, 'id' | 'timestamp'>) => {
    await addDoc(collection(db, "stockMovements"), { ...mvt, timestamp: serverTimestamp() });
  };

  const handleUpdatePO = useCallback(async (updatedPO: PurchaseOrder) => {
    const poRef = doc(db, "purchaseOrders", updatedPO.id);
    await updateDoc(poRef, { ...updatedPO });
    addLog(updatedPO.id, "PO updated.");
  }, []);

  const handleRegisterPart = async (partNumber: string, description: string, initialQty: number) => {
      const stockRef = doc(db, "stock", partNumber);
      await setDoc(stockRef, {
          partNumber,
          description,
          totalQuantity: initialQty,
          allocatedQuantity: 0,
          updatedAt: serverTimestamp()
      }, { merge: true });

      if (initialQty > 0) {
          await logStockMovement({
              partNumber,
              type: 'INWARD',
              quantity: initialQty,
              remarks: 'Initial stock registration'
          });
      }
  };

  const handleBulkStockUpload = async (items: { partNumber: string; description: string; quantity: number }[]) => {
      const batch = writeBatch(db);
      for (const item of items) {
          const stockRef = doc(db, "stock", item.partNumber);
          batch.set(stockRef, {
              partNumber: item.partNumber,
              description: item.description,
              totalQuantity: item.quantity,
              allocatedQuantity: 0,
              updatedAt: serverTimestamp()
          }, { merge: true });
      }
      await batch.commit();

      for (const item of items) {
          if (item.quantity > 0) {
              await logStockMovement({
                  partNumber: item.partNumber,
                  type: 'INWARD',
                  quantity: item.quantity,
                  remarks: 'Bulk inward upload'
              });
          }
      }
  };

  const handleInwardStock = async (partNumber: string, qty: number, remark: string) => {
    const stockRef = doc(db, "stock", partNumber);
    const existing = stock.find(s => s.partNumber === partNumber);
    const newTotal = (existing?.totalQuantity || 0) + qty;

    await setDoc(stockRef, {
        partNumber,
        description: existing?.description || 'Inward Entry',
        totalQuantity: newTotal,
        allocatedQuantity: existing?.allocatedQuantity || 0,
        updatedAt: serverTimestamp()
    }, { merge: true });

    await logStockMovement({
        partNumber,
        type: 'INWARD',
        quantity: qty,
        remarks: `Inward: ${remark}`
    });
  };

  const handleWalkingSale = async (partNumber: string, qty: number, remark: string) => {
    const stockRef = doc(db, "stock", partNumber);
    const existing = stock.find(s => s.partNumber === partNumber);
    if (!existing || (existing.totalQuantity - existing.allocatedQuantity) < qty) {
        alert("Insufficient available stock for walking sale.");
        return;
    }

    const newTotal = existing.totalQuantity - qty;
    await updateDoc(stockRef, { totalQuantity: newTotal, updatedAt: serverTimestamp() });

    await logStockMovement({
        partNumber,
        type: 'OUTWARD_WALKING',
        quantity: qty,
        remarks: `Walking Sale: ${remark}`
    });
  };

  const handleAllocateStock = async (poId: string, partNumber: string, qty: number) => {
    const targetPo = purchaseOrders.find(p => p.id === poId);
    const targetStock = stock.find(s => s.partNumber === partNumber);

    if (!targetPo || !targetStock) return;
    if ((targetStock.totalQuantity - targetStock.allocatedQuantity) < qty) {
        alert("Insufficient physical stock to allocate.");
        return;
    }

    const batch = writeBatch(db);

    const newItems = targetPo.items.map(item => {
        if (item.partNumber === partNumber) {
            return { ...item, allocatedQuantity: (item.allocatedQuantity || 0) + qty };
        }
        return item;
    });

    batch.update(doc(db, "purchaseOrders", poId), { items: newItems });
    batch.update(doc(db, "stock", partNumber), { 
        allocatedQuantity: (targetStock.allocatedQuantity || 0) + qty,
        updatedAt: serverTimestamp()
    });

    await batch.commit();
    await logStockMovement({
        partNumber,
        type: 'ALLOCATION',
        quantity: qty,
        referenceId: poId,
        remarks: `Allocated to PO #${targetPo.poNumber}`
    });
    addLog(poId, `Allocated ${qty} units of ${partNumber} from stock.`);
  };

  const handleSelectPO = useCallback((po: PurchaseOrder) => {
    setSelectedPO(po);
    setActiveModal('poDetail');
  }, []);

  const handleCloseModal = useCallback(() => {
    setActiveModal('none');
    setSelectedPO(null);
  }, []);

  const handleDashboardCardClick = useCallback((type: string) => {
    if (type === 'OPEN') setOrdersFilter({ status: OverallPOStatus.Open });
    else if (type === 'FULLY_AVAILABLE') setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.Fulfillment });
    else if (type === 'PARTIALLY_AVAILABLE') setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.Partial });
    else if (type === 'NOT_AVAILABLE') setOrdersFilter({ fulfillmentStatus: FulfillmentStatus.NotAvailable });
    setActivePane('allOrders');
  }, []);

  return (
    <div className="flex h-screen bg-slate-100 dark:bg-gray-900 text-slate-900 dark:text-slate-100 overflow-hidden">
       {firestoreError && <ErrorBanner projectId="maniranjan-po" message={firestoreError} onDismiss={() => setFirestoreError(null)} />}
      <Sidebar activePane={activePane} setActivePane={setActivePane} />
       <div className="flex-1 flex flex-col">
        <Header notifications={notifications} onMarkNotificationsAsRead={() => {}} theme={theme} setTheme={setTheme} />
        <main className="flex-1 overflow-y-auto bg-slate-50 dark:bg-slate-900">
            {activePane === 'dashboard' && <Dashboard purchaseOrders={purchaseOrders} filters={filters} setFilters={setFilters} customers={[]} onCardClick={handleDashboardCardClick} />}
            {activePane === 'allOrders' && <AllOrdersPane purchaseOrders={purchaseOrders} onSelectPO={handleSelectPO} onDeletePO={() => {}} filter={ordersFilter} onClearFilter={() => setOrdersFilter(null)} />}
            {activePane === 'stockManagement' && (
                <StockManagementPane 
                    stock={stock} 
                    purchaseOrders={purchaseOrders} 
                    movements={stockMovements}
                    onInward={handleInwardStock}
                    onWalkingSale={handleWalkingSale}
                    onAllocate={handleAllocateStock}
                    onRegisterPart={handleRegisterPart}
                    onBulkStockUpload={handleBulkStockUpload}
                />
            )}
            {activePane === 'upload' && <UploadPane onSaveSingleOrder={() => {}} onBulkUpload={() => {}} />}
            {activePane === 'analysis' && <AnalysisPane purchaseOrders={purchaseOrders} onSelectPO={handleSelectPO} />}
            {activePane === 'reports' && <ReportsPane purchaseOrders={purchaseOrders} onUpdatePO={handleUpdatePO} />}
            {activePane === 'dataManagement' && <DataManagementPane purchaseOrders={purchaseOrders} stock={stock} stockMovements={stockMovements} />}
        </main>
      </div>

       {selectedPO && (
        <POModal
          isOpen={activeModal === 'poDetail'}
          onClose={handleCloseModal}
          existingPO={selectedPO}
          logs={logs.filter(log => log.poId === selectedPO.id)}
          onUpdate={handleUpdatePO}
        />
       )}
    </div>
  );
}

export default App;

import React, { useState, useMemo } from 'react';
import { PurchaseOrder, StockItem, StockMovement } from '../types';
import { MAIN_BRANCHES, BRANCH_STRUCTURE } from '../constants';
import { TrashIcon, DatabaseIcon, ExclamationTriangleIcon } from './icons';
import { db } from '../services/firebase';
import { collection, query, where, getDocs, writeBatch } from 'firebase/firestore';
import ConfirmationModal from './ConfirmationModal';

interface DataManagementPaneProps {
  purchaseOrders: PurchaseOrder[];
  stock?: StockItem[];
  stockMovements?: StockMovement[];
}

const DataManagementPane: React.FC<DataManagementPaneProps> = ({ purchaseOrders, stock = [], stockMovements = [] }) => {
    const [selectedMainBranch, setSelectedMainBranch] = useState('');
    const [selectedSubBranch, setSelectedSubBranch] = useState('');

    // UI state for PO deletion
    const [confirmationOpen, setConfirmationOpen] = useState(false);
    const [isDeleting, setIsDeleting] = useState(false);

    // UI state for Stock deletion
    const [stockConfirmationOpen, setStockConfirmationOpen] = useState(false);
    const [isDeletingStock, setIsDeletingStock] = useState(false);

    const filteredCount = useMemo(() => {
        if (!selectedMainBranch) return 0;
        return purchaseOrders.filter(po => {
            if (po.mainBranch !== selectedMainBranch) return false;
            if (selectedSubBranch && po.subBranch !== selectedSubBranch) return false;
            return true;
        }).length;
    }, [purchaseOrders, selectedMainBranch, selectedSubBranch]);

    const handleMainBranchChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        setSelectedMainBranch(e.target.value);
        setSelectedSubBranch('');
    };

    const handleDeleteClick = () => {
        if (filteredCount === 0) return;
        setConfirmationOpen(true);
    };

    const handleDelete = async () => {
        setIsDeleting(true);
        try {
            const poRef = collection(db, "purchaseOrders");
            let q = query(poRef, where("mainBranch", "==", selectedMainBranch));
            if (selectedSubBranch) {
                q = query(q, where("subBranch", "==", selectedSubBranch));
            }
            const poSnapshot = await getDocs(q);

            if (poSnapshot.empty) {
                alert("No data found to delete on the server.");
                setIsDeleting(false);
                setConfirmationOpen(false);
                return;
            }

            const poIds = poSnapshot.docs.map(d => d.id);
            const refsToDelete: any[] = [];

            poSnapshot.docs.forEach(d => refsToDelete.push(d.ref));

            const promises = poIds.map(async (poId) => {
                const logQ = query(collection(db, "logs"), where("poId", "==", poId));
                const notifQ = query(collection(db, "notifications"), where("poId", "==", poId));
                const [logSnaps, notifSnaps] = await Promise.all([getDocs(logQ), getDocs(notifQ)]);
                return [...logSnaps.docs, ...notifSnaps.docs];
            });

            const relatedDocsResults = await Promise.all(promises);
            relatedDocsResults.forEach(docs => {
                docs.forEach(d => refsToDelete.push(d.ref));
            });

            const CHUNK_SIZE = 400;
            for (let i = 0; i < refsToDelete.length; i += CHUNK_SIZE) {
                const batch = writeBatch(db);
                const chunk = refsToDelete.slice(i, i + CHUNK_SIZE);
                chunk.forEach(ref => batch.delete(ref));
                await batch.commit();
            }

            setTimeout(() => {
                alert(`Successfully deleted ${filteredCount} orders and related data.`);
                setSelectedMainBranch('');
                setSelectedSubBranch('');
            }, 100);

        } catch (error) {
            console.error("Error deleting data:", error);
            alert("An error occurred while deleting data.");
        } finally {
            setIsDeleting(false);
            setConfirmationOpen(false);
        }
    };

    const handleClearStock = async () => {
        setIsDeletingStock(true);
        try {
            const stockSnapshot = await getDocs(collection(db, "stock"));
            const movementsSnapshot = await getDocs(collection(db, "stockMovements"));

            const refsToDelete = [
                ...stockSnapshot.docs.map(d => d.ref),
                ...movementsSnapshot.docs.map(d => d.ref)
            ];

            if (refsToDelete.length === 0) {
                alert("Inventory is already empty.");
                setIsDeletingStock(false);
                setStockConfirmationOpen(false);
                return;
            }

            const CHUNK_SIZE = 400;
            for (let i = 0; i < refsToDelete.length; i += CHUNK_SIZE) {
                const batch = writeBatch(db);
                const chunk = refsToDelete.slice(i, i + CHUNK_SIZE);
                chunk.forEach(ref => batch.delete(ref));
                await batch.commit();
            }

            alert("Inventory records and movement history wiped successfully.");
        } catch (error) {
            console.error("Error clearing stock:", error);
            alert("Failed to clear inventory.");
        } finally {
            setIsDeletingStock(false);
            setStockConfirmationOpen(false);
        }
    };

    return (
        <div className="container mx-auto p-4 sm:p-6 lg:p-8 space-y-8">
            <div className="flex items-center gap-4">
                <DatabaseIcon className="w-10 h-10 text-red-600" />
                <div>
                    <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">DATA MANAGEMENT</h2>
                    <p className="text-slate-500 dark:text-slate-400">Administrative tools for bulk cleanup and maintenance.</p>
                </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
                {/* Purchase Order Cleanup Card */}
                <div className="bg-white dark:bg-slate-800 p-8 rounded-2xl shadow-xl border border-slate-200 dark:border-slate-700 flex flex-col">
                    <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-6 border-b dark:border-slate-700 pb-4">Order Maintenance</h3>
                    <div className="space-y-6 flex-1">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div>
                                <label htmlFor="deleteMainBranch" className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1.5 uppercase tracking-tighter">Target Main Branch</label>
                                <select 
                                    id="deleteMainBranch" 
                                    value={selectedMainBranch} 
                                    onChange={handleMainBranchChange} 
                                    className="block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:outline-none focus:ring-red-500 focus:border-red-500"
                                >
                                    <option value="">Select Main Branch</option>
                                    {MAIN_BRANCHES.map(b => <option key={b} value={b}>{b}</option>)}
                                </select>
                            </div>
                            <div>
                                <label htmlFor="deleteSubBranch" className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1.5 uppercase tracking-tighter">Sub Branch (Optional)</label>
                                <select 
                                    id="deleteSubBranch" 
                                    value={selectedSubBranch} 
                                    onChange={(e) => setSelectedSubBranch(e.target.value)} 
                                    disabled={!selectedMainBranch} 
                                    className="block w-full text-base px-3 py-2.5 rounded-lg border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:outline-none focus:ring-red-500 focus:border-red-500 disabled:opacity-50"
                                >
                                    <option value="">All Sub Branches</option>
                                    {selectedMainBranch && BRANCH_STRUCTURE[selectedMainBranch]?.map(sb => <option key={sb} value={sb}>{sb}</option>)}
                                </select>
                            </div>
                        </div>

                        {selectedMainBranch && (
                            <div className="bg-red-50 dark:bg-red-900/10 p-6 rounded-xl border border-red-200 dark:border-red-800/50 flex flex-col items-center justify-center text-center space-y-4">
                                <div>
                                    <p className="text-base font-medium text-slate-800 dark:text-slate-100">
                                        Found <span className="text-red-600 dark:text-red-400 font-black text-3xl mx-1">{filteredCount}</span> match(es)
                                    </p>
                                    <p className="text-xs text-slate-600 dark:text-slate-400 mt-1 uppercase font-bold tracking-widest">
                                        {selectedMainBranch} {selectedSubBranch ? `/ ${selectedSubBranch}` : ''}
                                    </p>
                                </div>
                                <button
                                    onClick={handleDeleteClick}
                                    disabled={filteredCount === 0 || isDeleting}
                                    className="w-full flex items-center justify-center gap-2 px-6 py-3 text-base font-bold text-white bg-red-600 rounded-lg hover:bg-red-700 focus:outline-none shadow-md transition-all active:scale-95 disabled:opacity-50"
                                >
                                    <TrashIcon className="w-5 h-5" />
                                    {isDeleting ? 'Processing...' : 'Delete Selected Records'}
                                </button>
                                <p className="text-[10px] text-red-500 dark:text-red-400 italic">
                                    Deleting orders also wipes linked activity logs and notifications.
                                </p>
                            </div>
                        )}
                    </div>
                </div>

                {/* Inventory Cleanup Card */}
                <div className="bg-white dark:bg-slate-800 p-8 rounded-2xl shadow-xl border border-slate-200 dark:border-slate-700 flex flex-col">
                    <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-6 border-b dark:border-slate-700 pb-4">Global Inventory Cleanup</h3>
                    <div className="space-y-6 flex-1 flex flex-col justify-center">
                        <div className="text-center space-y-2">
                             <div className="p-4 bg-slate-100 dark:bg-slate-900/50 rounded-full w-20 h-20 flex items-center justify-center mx-auto mb-4">
                                <DatabaseIcon className="w-10 h-10 text-slate-400" />
                            </div>
                            <p className="text-lg font-bold text-slate-800 dark:text-slate-100">Wipe All Stock & Movements</p>
                            <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm mx-auto">
                                This will remove every registered part number and all associated inward/outward movement history logs globally.
                            </p>
                        </div>

                        <div className="p-4 bg-amber-50 dark:bg-amber-900/10 rounded-xl border border-amber-200 dark:border-amber-800/30 flex items-start gap-3">
                             <ExclamationTriangleIcon className="w-5 h-5 text-amber-500 flex-shrink-0 mt-0.5" />
                             <p className="text-xs text-amber-700 dark:text-amber-400 font-medium">
                                Active Purchase Orders containing these parts will show "Unavailable" stock status after this action.
                             </p>
                        </div>

                        <button
                            onClick={() => setStockConfirmationOpen(true)}
                            disabled={isDeletingStock}
                            className="w-full flex items-center justify-center gap-2 px-6 py-3 text-base font-bold text-white bg-slate-800 dark:bg-slate-700 rounded-lg hover:bg-red-600 transition-colors shadow-md active:scale-95 disabled:opacity-50"
                        >
                            <TrashIcon className="w-5 h-5" />
                            {isDeletingStock ? 'Clearing Inventory...' : 'Wipe Global Stock Data'}
                        </button>
                    </div>
                </div>
            </div>

            {/* PO Deletion Confirmation */}
            <ConfirmationModal
                isOpen={confirmationOpen}
                onClose={() => !isDeleting && setConfirmationOpen(false)}
                onConfirm={handleDelete}
                title="Confirm Data Removal"
            >
                <div className="space-y-3">
                    <p className="font-medium">You are about to delete <strong>{filteredCount}</strong> purchase orders for <strong>{selectedMainBranch}</strong>.</p>
                    <p className="text-xs text-slate-500">This action is irreversible and includes all linked logs and notifications.</p>
                </div>
            </ConfirmationModal>

            {/* Global Stock Wipe Confirmation */}
            <ConfirmationModal
                isOpen={stockConfirmationOpen}
                onClose={() => !isDeletingStock && setStockConfirmationOpen(false)}
                onConfirm={handleClearStock}
                title="Wipe Entire Inventory?"
            >
                <div className="space-y-3">
                    <p className="font-bold text-red-600">WARNING: CRITICAL ACTION</p>
                    <p>Are you absolutely sure you want to delete <strong>ALL</strong> parts and <strong>ALL</strong> history logs from the global database?</p>
                    <p className="text-xs text-slate-500 italic">This cannot be undone. All stock levels will be reset to zero and parts must be re-registered.</p>
                </div>
            </ConfirmationModal>
        </div>
    );
};

